def sort_rfid_channels(chs: List[str]) -> List[str]:
    nums = sorted([c for c in chs if c.isdigit()], key=lambda x: int(x))
    letters = sorted([c for c in chs if c.isalpha()], key=lambda x: x.upper())
    return nums + letters


RFID_CHANNELS = sort_rfid_channels(RFID_CHANNELS)


def normalize_channel(token: str) -> str:
    t = token.strip()
    if t.upper().startswith("TTL"):
        rest = t[3:]
        if rest.isdigit():
            return rest
    return t


def safe_slug(s: str, fallback: str = "experiment") -> str:
    s = (s or "").strip()
    if not s:
        return fallback
    s = re.sub(r"\s+", "_", s)
    s = re.sub(r"[^A-Za-z0-9._-]", "", s)
    return s or fallback


def sanitize_token(s: str, fallback: str = "") -> str:
    s = (s or "").strip()
    if not s:
        return fallback
    s = re.sub(r"[^\w\-]", "_", s)
    s = re.sub(r"_+", "_", s).strip("_")
    return s or fallback


def parse_daq_line_bytes(line: bytes) -> Tuple[str, str, str]:
    s = line.decode("ascii", errors="ignore").strip()
    parts = s.split(" ")
    if len(parts) != 3:
        raise ValueError("Bad line")
    ch = normalize_channel(parts[0])
    tag = parts[1]
    daq_t = parts[2]
    return ch, tag, daq_t


def make_spinbox(vmin: int, vmax: int, value: int, step: int = 1) -> QSpinBox:
    sb = QSpinBox()
    sb.setRange(int(vmin), int(vmax))
    sb.setSingleStep(int(step))
    sb.setValue(int(value))
    sb.setAccelerated(True)
    sb.setKeyboardTracking(False)
    sb.setFocusPolicy(Qt.StrongFocus)
    sb.setButtonSymbols(QSpinBox.UpDownArrows)
    return sb


