def led_style(active: bool) -> str:
    color = "#2ecc71" if active else "#b0b0b0"
    border = "#1e8449" if active else "#7a7a7a"
    return (
        "min-width:12px; min-height:12px; max-width:12px; max-height:12px;"
        f"border-radius:6px; background:{color}; border:1px solid {border};"
    )


def seconds_to_ddhhmm(seconds: float) -> Tuple[int, int, int]:
    seconds = max(0.0, float(seconds))
    total_min = int(round(seconds / 60.0))
    dd = total_min // (24 * 60)
    rem = total_min % (24 * 60)
    hh = rem // 60
    mm = rem % 60
    return dd, hh, mm


def ddhhmm_to_seconds(dd: int, hh: int, mm: int) -> int:
    dd = max(0, int(dd))
    hh = max(0, int(hh))
    mm = max(0, int(mm))
    return dd * 86400 + hh * 3600 + mm * 60


def read_one_rfid_event_from_port(port: str, baud: int = 115200, timeout_s: float = 90.0) -> Optional[Tuple[str, str]]:
    """Returns (channel, tag) for first RFID event observed; ignores TTL lines."""
    ser = None
    try:
        ser = serial.Serial(port, baud, timeout=0.2)
        try:
            ser.reset_input_buffer()
        except Exception:
            pass
        time.sleep(0.2)
        try:
            ser.write(b"READC")
        except Exception:
            pass

        buf = b""
        deadline = time.time() + timeout_s
        while time.time() < deadline:
            chunk = ser.read(1024)
            if not chunk:
                continue
            buf += chunk
            while b"\r\n" in buf:
                raw, buf = buf.split(b"\r\n", 1)
                if not raw:
                    continue
                try:
                    ch, tag, _ = parse_daq_line_bytes(raw)
                    if ch not in TTL_CHANNELS:
                        return ch, tag
                except Exception:
                    pass
        return None
    except Exception:
        return None
    finally:
        try:
            if ser:
                ser.close()
        except Exception:
            pass


