# DAQ acquisition
# -----------------------------
class BoardAcquisition:
    def __init__(
        self,
        port: str,
        save_dir: str,
        file_prefix: str,
        baudrate: int = 115200,
        serial_timeout_s: float = 0.1,
        max_queue: int = 200_000,
        flush_interval_s: float = 1.0,
        batch_size: int = 2000,
        send_start_command: bytes = b"READC",
    ):
        self.port = port
        self.save_dir = str(Path(save_dir))
        Path(self.save_dir).mkdir(parents=True, exist_ok=True)
        self.data_file = Path(self.save_dir) / f"{file_prefix}_antenna_data.csv"
        self.raw_serial_file = Path(self.save_dir) / f"{file_prefix}_daq_raw_serial.log"
        self.unparsed_file = Path(self.save_dir) / f"{file_prefix}_daq_unparsed_lines.log"

        self.baudrate = baudrate
        self.serial_timeout_s = serial_timeout_s
        self.flush_interval_s = flush_interval_s
        self.batch_size = batch_size
        self.send_start_command = send_start_command

        self._q: "queue.Queue[Optional[str]]" = queue.Queue(maxsize=max_queue)
        self._stop = threading.Event()
        self._ser: Optional[serial.Serial] = None
        self._reader_t: Optional[threading.Thread] = None
        self._writer_t: Optional[threading.Thread] = None

        self.lines_ok = 0
        self.lines_bad = 0
        self.lines_dropped = 0
        self.bytes_read = 0
        self.ttl_counts: Dict[str, int] = {ch: 0 for ch in TTL_CHANNELS}
        self.last_raw_line = ""
        self.last_bad_line = ""
        self._running = False

        self._status_lock = threading.Lock()
        self._status: Dict[str, Dict[str, Any]] = {ch: {"t": 0.0, "tag": ""} for ch in (TTL_CHANNELS + RFID_CHANNELS)}
        self._status_last_update = {ch: 0.0 for ch in self._status.keys()}

        self._tag_lock = threading.Lock()
        self._tag_counts: Dict[str, int] = {}

        self._rfid_lock = threading.Lock()
        self._rfid_event_counter = 0
        self._rfid_last_tag = ""
        self._rfid_last_ch = ""

    def start(self) -> None:
        if self._running:
            return
        self._stop.clear()

        self._ser = serial.Serial(self.port, self.baudrate, timeout=self.serial_timeout_s)
        try:
            self._ser.set_buffer_size(rx_size=1024 * 1024, tx_size=256 * 1024)
        except Exception:
            pass

        try:
            self._ser.reset_input_buffer()
        except Exception:
            pass

        time.sleep(0.2)
        if self.send_start_command:
            try:
                self._ser.write(self.send_start_command)
            except Exception:
                pass

        self._writer_t = threading.Thread(target=self._writer_loop, daemon=True)
        self._reader_t = threading.Thread(target=self._reader_loop, daemon=True)
        self._writer_t.start()
        self._reader_t.start()
        self._running = True

    def request_stop(self) -> None:
        self._stop.set()
        try:
            if self._ser and self._ser.is_open:
                self._ser.close()
        except Exception:
            pass

    def is_running(self) -> bool:
        if not self._running:
            return False
        if self._reader_t and self._reader_t.is_alive():
            return True
        if self._writer_t and self._writer_t.is_alive():
            return True
        self._running = False
        return False

    def get_status_snapshot(self) -> Dict[str, Dict[str, Any]]:
        with self._status_lock:
            return {k: dict(v) for k, v in self._status.items()}

    def get_tag_counts_snapshot(self) -> Dict[str, int]:
        with self._tag_lock:
            return dict(self._tag_counts)

    def get_last_rfid_event(self) -> Tuple[int, str, str]:
        with self._rfid_lock:
            return self._rfid_event_counter, self._rfid_last_tag, self._rfid_last_ch

    def _update_status(self, ch: str, tag: str, now: float) -> None:
        if ch not in self._status:
            return
        if now - self._status_last_update[ch] < STATUS_UPDATE_MIN_INTERVAL_S:
            return
        self._status_last_update[ch] = now
        with self._status_lock:
            self._status[ch]["t"] = now
            self._status[ch]["tag"] = tag

    def _merge_tag_counts(self, local_counts: Dict[str, int]) -> None:
        if not local_counts:
            return
        with self._tag_lock:
            for k, v in local_counts.items():
                self._tag_counts[k] = self._tag_counts.get(k, 0) + v
        local_counts.clear()

    def _note_rfid_event(self, ch: str, tag: str) -> None:
        with self._rfid_lock:
            self._rfid_event_counter += 1
            self._rfid_last_tag = tag
            self._rfid_last_ch = ch

    def _reader_loop(self) -> None:
        buf = b""
        local_counts: Dict[str, int] = {}
        last_merge = time.monotonic()

        raw_f = None
        bad_f = None
        try:
            raw_f = open(self.raw_serial_file, "a", encoding="utf-8", buffering=1)
            bad_f = open(self.unparsed_file, "a", encoding="utf-8", buffering=1)
            raw_f.write(f"----- DAQ raw serial start {dt.datetime.now().isoformat()} -----\n")
            bad_f.write(f"----- DAQ unparsed start {dt.datetime.now().isoformat()} -----\n")

            while not self._stop.is_set():
                n = self._ser.in_waiting if self._ser else 0
                chunk = self._ser.read(n if n > 0 else 1)
                if not chunk:
                    now = time.monotonic()
                    if now - last_merge >= TAG_MERGE_INTERVAL_S:
                        self._merge_tag_counts(local_counts)
                        last_merge = now
                    continue

                self.bytes_read += len(chunk)
                buf += chunk

                while b"\r\n" in buf:
                    raw, buf = buf.split(b"\r\n", 1)
                    if not raw:
                        continue

                    raw_text = raw.decode("ascii", errors="replace").strip()
                    self.last_raw_line = raw_text
                    try:
                        raw_f.write(f"{dt.datetime.now().isoformat()};{raw_text}\n")
                    except Exception:
                        pass

                    try:
                        ch, tag, daq_t = parse_daq_line_bytes(raw)
                        out = f"{ch};{tag};{daq_t};{dt.datetime.now().isoformat()}\n"

                        try:
                            self._q.put_nowait(out)
                            self.lines_ok += 1
                        except queue.Full:
                            self.lines_dropped += 1

                        now = time.monotonic()
                        self._update_status(ch, tag, now)

                        if ch in TTL_CHANNELS:
                            self.ttl_counts[ch] = self.ttl_counts.get(ch, 0) + 1
                        else:
                            local_counts[tag] = local_counts.get(tag, 0) + 1
                            self._note_rfid_event(ch, tag)

                        if now - last_merge >= TAG_MERGE_INTERVAL_S:
                            self._merge_tag_counts(local_counts)
                            last_merge = now

                    except Exception as e:
                        self.lines_bad += 1
                        self.last_bad_line = raw_text
                        try:
                            bad_f.write(f"{dt.datetime.now().isoformat()};{raw_text};{e}\n")
                        except Exception:
                            pass

        except Exception:
            pass
        finally:
            try:
                self._merge_tag_counts(local_counts)
            except Exception:
                pass
            try:
                self._q.put_nowait(None)
            except Exception:
                pass
            for fh in (raw_f, bad_f):
                try:
                    if fh:
                        fh.write(f"----- DAQ serial end {dt.datetime.now().isoformat()} -----\n")
                        fh.flush()
                        fh.close()
                except Exception:
                    pass

    def _writer_loop(self) -> None:
        flush_deadline = time.monotonic() + self.flush_interval_s
        batch: List[str] = []
        with open(self.data_file, "a", newline="", buffering=1024 * 1024) as f:
            while True:
                if self._stop.is_set() and self._q.empty():
                    break
                try:
                    item = self._q.get(timeout=0.2)
                except queue.Empty:
                    item = None

                if item is not None:
                    batch.append(item)

                now = time.monotonic()
                if batch and (len(batch) >= self.batch_size or now >= flush_deadline):
                    f.writelines(batch)
                    f.flush()
                    batch.clear()
                    flush_deadline = now + self.flush_interval_s

                if item is None and self._stop.is_set():
                    break

            if batch:
                f.writelines(batch)
                f.flush()


# -----------------------------
# Encoding options (concise)
# -----------------------------
def gbday_to_kbps(gb_per_day: float) -> int:
    bps = gb_per_day * 1e9 * 8 / 86400.0
    return int(round(bps / 1000.0))


@dataclass(frozen=True)
class EncodingOption:
    short_label: str
    full_label: str
    out_ext: str
    segment_override_s: Optional[int]
    builder: Any


def build_deepecohab_default_nvenc(w: int, h: int, fps: int, seg: int, out: str) -> List[str]:
    return [
        "-c:v", "hevc_nvenc",
        "-preset", "slow",
        "-tune", "hq",
        "-rc:v", "vbr",
        "-cq:v", "22",
        "-b:v", "0",
        "-spatial_aq", "1",
        "-aq-strength", "4",
        "-rc-lookahead", "10",
        "-g", "5",
        "-force_key_frames", "expr:gte(t,n_forced*6)",
        "-segment_time", str(seg),
        "-f", "segment",
        "-an",
        out
    ]


def build_x265_capped(w: int, h: int, fps: int, seg: int, out: str, gb_day: float, crf: int) -> List[str]:
    target_kbps = gbday_to_kbps(gb_day)
    buf_kbps = int(target_kbps * 2)
    x265_params = f"crf={crf}:vbv-maxrate={target_kbps}:vbv-bufsize={buf_kbps}:aq-mode=3"
    return [
        "-c:v", "libx265",
        "-preset", "slow",
        "-x265-params", x265_params,
        "-pix_fmt", "yuv420p",
        "-movflags", "+faststart",
        "-f", "segment",
        "-segment_time", str(seg),
        "-reset_timestamps", "1",
        "-segment_format", "mp4",
        out
    ]


def build_nvenc_capped(w: int, h: int, fps: int, seg: int, out: str, gb_day: float, cq: int) -> List[str]:
    target_kbps = gbday_to_kbps(gb_day)
    buf_kbps = int(target_kbps * 2)
    return [
        "-c:v", "hevc_nvenc",
        "-preset", "p7",
        "-tune", "hq",
        "-rc:v", "vbr",
        "-cq:v", str(cq),
        "-b:v", f"{target_kbps}k",
        "-maxrate:v", f"{target_kbps}k",
        "-bufsize:v", f"{buf_kbps}k",
        "-spatial_aq", "1",
        "-aq-strength", "4",
        "-rc-lookahead", "20",
        "-g", "60",
        "-pix_fmt", "yuv420p",
        "-movflags", "+faststart",
        "-f", "segment",
        "-segment_time", str(seg),
        "-reset_timestamps", "1",
        "-segment_format", "mp4",
        out
    ]


def make_encoding_options() -> List[EncodingOption]:
    out: List[EncodingOption] = []
    out.append(EncodingOption(
        short_label="DeepEcoHAB_default (NVENC HQ)",
        full_label="GPU HEVC NVENC | CQ=22 | preset=slow | AQ=4 | seg=1h",
        out_ext="mp4",
        segment_override_s=3600,
        builder=build_deepecohab_default_nvenc,
    ))
    caps = [(175.0, 14, 16), (125.0, 15, 18), (75.0, 16, 20)]
    for gb, crf, cq in caps:
        kbps = gbday_to_kbps(gb)
        out.append(EncodingOption(
            short_label=f"CPU x265 ~{int(gb)}GB/day",
            full_label=f"CPU x265 | CRF={crf} | vbv~{kbps}k | preset=slow",
            out_ext="mp4",
            segment_override_s=None,
            builder=lambda w, h, fps, seg, outp, gb=gb, crf=crf: build_x265_capped(w, h, fps, seg, outp, gb_day=gb, crf=crf),
        ))
        out.append(EncodingOption(
            short_label=f"GPU NVENC ~{int(gb)}GB/day",
            full_label=f"GPU NVENC | CQ={cq} | vbv~{kbps}k | preset=p7",
            out_ext="mp4",
            segment_override_s=None,
            builder=lambda w, h, fps, seg, outp, gb=gb, cq=cq: build_nvenc_capped(w, h, fps, seg, outp, gb_day=gb, cq=cq),
        ))
    return out


ENCODING_OPTIONS = make_encoding_options()


def build_ffmpeg_cmd(opt: EncodingOption, width: int, height: int, fps: int, seg_s: int, out_pattern: str) -> List[str]:
    base = [
        "ffmpeg", "-y",
        "-hide_banner", "-loglevel", "warning",
        "-f", "rawvideo",
        "-vcodec", "rawvideo",
        "-pix_fmt", "gray",
        "-s", f"{width}x{height}",
        "-r", str(fps),
        "-i", "-"
    ]
    return base + opt.builder(width, height, fps, seg_s, out_pattern)


# -----------------------------
# Camera ROI centering
# -----------------------------
def try_set_enum(nodemap, node_name: str, entry_name: str) -> bool:
    node = PySpin.CEnumerationPtr(nodemap.GetNode(node_name))
    if not PySpin.IsReadable(node) or not PySpin.IsWritable(node):
        return False
    entry = PySpin.CEnumEntryPtr(node.GetEntryByName(entry_name))
    if not PySpin.IsReadable(entry):
        return False
    node.SetIntValue(entry.GetValue())
    return True


def try_get_enum(nodemap, node_name: str) -> str:
    try:
        node = PySpin.CEnumerationPtr(nodemap.GetNode(node_name))
        if not PySpin.IsReadable(node):
            return ""
        entry = PySpin.CEnumEntryPtr(node.GetCurrentEntry())
        if not PySpin.IsReadable(entry):
            return ""
        return str(entry.GetSymbolic())
    except Exception:
        return ""


def try_set_bool(nodemap, node_name: str, value: bool) -> bool:
    try:
        node = PySpin.CBooleanPtr(nodemap.GetNode(node_name))
        if not PySpin.IsReadable(node) or not PySpin.IsWritable(node):
            return False
        node.SetValue(bool(value))
        return True
    except Exception:
        return False


def try_set_float(nodemap, node_name: str, value: float) -> bool:
    try:
        node = PySpin.CFloatPtr(nodemap.GetNode(node_name))
        if not PySpin.IsReadable(node) or not PySpin.IsWritable(node):
            return False
        v = max(float(node.GetMin()), min(float(node.GetMax()), float(value)))
        node.SetValue(v)
        return True
    except Exception:
        return False


def configure_camera_external_trigger(
    nodemap,
    source: str = "Line0",
    activation: str = "RisingEdge",
    delay_us: float = 24.0,
    overlap: str = "ReadOut",
) -> Dict[str, Any]:
    """Force a Blackfly/Spinnaker camera into external FrameStart trigger mode.

    The GUI previously relied on whatever had been saved in SpinView. That is fragile
    because PySpin initialization and different PCs/cameras can leave the camera in
    another state. This helper applies the critical trigger nodes every time before
    BeginAcquisition().
    """
    report: Dict[str, Any] = {
        "requested_source": source,
        "requested_activation": activation,
        "requested_delay_us": float(delay_us),
        "requested_overlap": overlap,
        "steps": {},
    }

    # TriggerMode usually must be Off before changing TriggerSource/Activation.
    report["steps"]["TriggerMode_Off"] = try_set_enum(nodemap, "TriggerMode", "Off")

    if source.startswith("Line"):
        report["steps"]["LineSelector"] = try_set_enum(nodemap, "LineSelector", source)
        report["steps"]["LineMode_Input"] = try_set_enum(nodemap, "LineMode", "Input")
        report["steps"]["LineInverter_False"] = try_set_bool(nodemap, "LineInverter", False)

    report["steps"]["TriggerSelector_FrameStart"] = try_set_enum(nodemap, "TriggerSelector", "FrameStart")
    report["steps"]["TriggerSource"] = try_set_enum(nodemap, "TriggerSource", source)
    report["steps"]["TriggerActivation"] = try_set_enum(nodemap, "TriggerActivation", activation)
    report["steps"]["TriggerOverlap"] = try_set_enum(nodemap, "TriggerOverlap", overlap)
    report["steps"]["TriggerDelay"] = try_set_float(nodemap, "TriggerDelay", float(delay_us))
    report["steps"]["TriggerMode_On"] = try_set_enum(nodemap, "TriggerMode", "On")

    # Read back the key nodes so the status/log can expose what the camera actually accepted.
    report["readback"] = {
        "TriggerMode": try_get_enum(nodemap, "TriggerMode"),
        "TriggerSelector": try_get_enum(nodemap, "TriggerSelector"),
        "TriggerSource": try_get_enum(nodemap, "TriggerSource"),
        "TriggerActivation": try_get_enum(nodemap, "TriggerActivation"),
        "TriggerOverlap": try_get_enum(nodemap, "TriggerOverlap"),
    }
    if source.startswith("Line"):
        report["readback"]["LineSelector"] = try_get_enum(nodemap, "LineSelector")
        report["readback"]["LineMode"] = try_get_enum(nodemap, "LineMode")
    return report


def _align_down(value: int, inc: int) -> int:
    if inc <= 1:
        return int(value)
    return int(value // inc * inc)


def _clamp(value: int, vmin: int, vmax: int) -> int:
    return max(vmin, min(vmax, int(value)))


def set_centered_roi(nodemap, req_w: Optional[int], req_h: Optional[int]) -> None:
    if not req_w and not req_h:
        return
    try:
        w_node = PySpin.CIntegerPtr(nodemap.GetNode("Width"))
        h_node = PySpin.CIntegerPtr(nodemap.GetNode("Height"))
        ox_node = PySpin.CIntegerPtr(nodemap.GetNode("OffsetX"))
        oy_node = PySpin.CIntegerPtr(nodemap.GetNode("OffsetY"))
    except Exception:
        return

    if not (PySpin.IsWritable(w_node) and PySpin.IsWritable(h_node) and PySpin.IsWritable(ox_node) and PySpin.IsWritable(oy_node)):
        return

    try:
        ox_node.SetValue(int(ox_node.GetMin()))
        oy_node.SetValue(int(oy_node.GetMin()))
    except Exception:
        pass

    try:
        w_min, w_max = int(w_node.GetMin()), int(w_node.GetMax())
        h_min, h_max = int(h_node.GetMin()), int(h_node.GetMax())
        w_inc = int(getattr(w_node, "GetInc")() or 1)
        h_inc = int(getattr(h_node, "GetInc")() or 1)

        if req_w:
            w_set = _align_down(_clamp(req_w, w_min, w_max), max(1, w_inc))
            w_node.SetValue(w_set)
        if req_h:
            h_set = _align_down(_clamp(req_h, h_min, h_max), max(1, h_inc))
            h_node.SetValue(h_set)

        cur_w = int(w_node.GetValue())
        cur_h = int(h_node.GetValue())
        max_w = int(w_node.GetMax())
        max_h = int(h_node.GetMax())

        off_x = (max_w - cur_w) // 2
        off_y = (max_h - cur_h) // 2

        ox_min, ox_max = int(ox_node.GetMin()), int(ox_node.GetMax())
        oy_min, oy_max = int(oy_node.GetMin()), int(oy_node.GetMax())
        ox_inc = int(getattr(ox_node, "GetInc")() or 1)
        oy_inc = int(getattr(oy_node, "GetInc")() or 1)

        off_x = _align_down(_clamp(off_x, ox_min, ox_max), max(1, ox_inc))
        off_y = _align_down(_clamp(off_y, oy_min, oy_max), max(1, oy_inc))

        ox_node.SetValue(off_x)
        oy_node.SetValue(off_y)
    except Exception:
        return


# -----------------------------
# Camera worker
# -----------------------------
class CameraWorker:
    def __init__(
        self,
        save_dir: str,
        file_prefix: str,
        fps: int,
        segment_time_s: int,
        preview_enabled: bool,
        preview_max_fps: int,
        target_width: int,
        target_height: int,
        software_resize_if_needed: bool,
        encoding_index: int,
        force_external_trigger: bool = True,
        trigger_source: str = "Line0",
        trigger_activation: str = "RisingEdge",
        trigger_delay_us: float = 24.0,
    ):
        self.save_dir = str(Path(save_dir))
        Path(self.save_dir).mkdir(parents=True, exist_ok=True)

        self.file_prefix = file_prefix
        self.fps = int(fps)
        self.segment_time_s = int(segment_time_s)

        self.preview_enabled = bool(preview_enabled)
        self.preview_max_fps = max(1, int(preview_max_fps))

        self.target_width = int(target_width) if target_width else None
        self.target_height = int(target_height) if target_height else None
        self.software_resize_if_needed = bool(software_resize_if_needed)

        self.opt = ENCODING_OPTIONS[int(encoding_index)]

        self.force_external_trigger = bool(force_external_trigger)
        self.trigger_source = str(trigger_source or "Line0")
        self.trigger_activation = str(trigger_activation or "RisingEdge")
        self.trigger_delay_us = float(trigger_delay_us)
        self.camera_config_report: Dict[str, Any] = {}

        self.stop_event = threading.Event()
        self._thread: Optional[threading.Thread] = None
        self._running = False

        self.frames_written = 0
        self.frames_total = 0
        self.last_error = ""
        self.waiting_for_first_frame = True

        self.actual_width: Optional[int] = None
        self.actual_height: Optional[int] = None
        self.record_width: Optional[int] = None
        self.record_height: Optional[int] = None

        self._preview_lock = threading.Lock()
        self._preview_frame: Optional[np.ndarray] = None

        self.ffmpeg_log = Path(self.save_dir) / f"{self.file_prefix}_ffmpeg.log"
        self.timestamps_path = Path(self.save_dir) / f"{self.file_prefix}_timestamps.txt"
        self.ffmpeg_restarts = 0
        self.frames_dropped = 0
        self.writer_queue_size = 0
        self.last_frame_monotonic = 0.0
        self.last_write_monotonic = 0.0

    def start(self) -> None:
        if self._running:
            return
        self.stop_event.clear()
        self._thread = threading.Thread(target=self._run, daemon=True)
        self._thread.start()
        self._running = True

    def request_stop(self) -> None:
        self.stop_event.set()

    def is_running(self) -> bool:
        if not self._running:
            return False
        if self._thread and self._thread.is_alive():
            return True
        self._running = False
        return False

    def get_preview_frame(self) -> Optional[np.ndarray]:
        with self._preview_lock:
            return None if self._preview_frame is None else self._preview_frame.copy()

    @staticmethod
    def _is_timeout_exc(e: Exception) -> bool:
        s = str(e).lower()
        return ("timeout" in s) or ("-1011" in s) or ("spinnaker_err_timeout" in s)

    def _stop_ffmpeg_safely(self, proc: Optional[subprocess.Popen], logf: Optional[Any]) -> None:
        if proc is None:
            if logf:
                try:
                    logf.flush(); logf.close()
                except Exception:
                    pass
            return
        try:
            if proc.stdin:
                proc.stdin.close()
        except Exception:
            pass
        try:
            proc.wait(timeout=20)
        except Exception:
            try:
                proc.terminate()
            except Exception:
                pass
            try:
                proc.wait(timeout=5)
            except Exception:
                try:
                    proc.kill()
                except Exception:
                    pass
        if logf:
            try:
                logf.write(f"----- FFmpeg end {dt.datetime.now().isoformat()} -----\n")
                logf.flush(); logf.close()
            except Exception:
                pass

    def _start_ffmpeg(self, width: int, height: int) -> Tuple[Optional[subprocess.Popen], Optional[Any]]:
        seg_s = self.opt.segment_override_s if self.opt.segment_override_s else self.segment_time_s

        # First encoder run keeps the historic file naming. Every automatic
        # restart uses a "partXXX" infix so that a recovered FFmpeg process can
        # never overwrite earlier segments.
        part_idx = int(self.ffmpeg_restarts)
        if part_idx <= 0:
            out_pattern = str(Path(self.save_dir) / f"{self.file_prefix}_%03d.{self.opt.out_ext}")
        else:
            out_pattern = str(Path(self.save_dir) / f"{self.file_prefix}_part{part_idx:03d}_%03d.{self.opt.out_ext}")

        cmd = build_ffmpeg_cmd(self.opt, width, height, self.fps, seg_s, out_pattern)

        logf = open(self.ffmpeg_log, "a", buffering=1)
        logf.write(f"\n\n----- FFmpeg start part={part_idx} {dt.datetime.now().isoformat()} -----\n")
        logf.write(" ".join(cmd) + "\n")

        proc = subprocess.Popen(
            cmd, stdin=subprocess.PIPE, stdout=logf, stderr=logf,
            bufsize=1024 * 1024 * 8,
        )
        time.sleep(0.25)
        if proc.poll() is not None:
            logf.write(f"FFmpeg exited early with code {proc.returncode}\n")
            logf.flush(); logf.close()
            return None, None

        self.ffmpeg_restarts += 1
        self.last_write_monotonic = time.monotonic()
        return proc, logf

    def _run(self) -> None:
        system = PySpin.System.GetInstance()
        cam_list = None
        cam = None
        proc = None
        logf = None
        timestamp_f = None
        last_preview_update = 0.0
        writer_q: "queue.Queue[Optional[np.ndarray]]" = queue.Queue(maxsize=1800)  # ~60 s at 30 fps
        writer_stop = threading.Event()
        writer_state: Dict[str, Any] = {"proc": None, "logf": None, "last_restart": 0.0}
        writer_thread: Optional[threading.Thread] = None

        def stop_proc_from_watchdog(reason: str) -> None:
            """Kill the active FFmpeg process from the camera thread to unblock a stuck writer thread."""
            try:
                p = writer_state.get("proc")
                lf = writer_state.get("logf")
                if lf:
                    lf.write(f"\n----- FFmpeg watchdog: {reason} at {dt.datetime.now().isoformat()} -----\n")
                    lf.flush()
                if p is not None and p.poll() is None:
                    try:
                        p.kill()
                    except Exception:
                        pass
            except Exception:
                pass

        def writer_loop(width: int, height: int) -> None:
            nonlocal proc, logf
            proc, logf = self._start_ffmpeg(width, height)
            writer_state["proc"] = proc
            writer_state["logf"] = logf
            writer_state["last_restart"] = time.monotonic()

            if proc is None:
                self.last_error = f"FFmpeg failed to start. See log: {self.ffmpeg_log}"
                return

            pending: Optional[np.ndarray] = None

            while (not writer_stop.is_set()) or pending is not None or (not writer_q.empty()):
                try:
                    if pending is None:
                        try:
                            pending = writer_q.get(timeout=0.5)
                        except queue.Empty:
                            pending = None

                    if pending is None:
                        if proc is not None and proc.poll() is not None:
                            self.last_error = f"FFmpeg exited with code {proc.returncode}; restarting encoder."
                            self._stop_ffmpeg_safely(proc, logf)
                            proc, logf = self._start_ffmpeg(width, height)
                            writer_state["proc"] = proc
                            writer_state["logf"] = logf
                            writer_state["last_restart"] = time.monotonic()
                            if proc is None:
                                return
                        continue

                    if proc is None or proc.poll() is not None or not proc.stdin:
                        if proc is not None:
                            self.last_error = f"FFmpeg exited with code {proc.returncode}; restarting encoder."
                            self._stop_ffmpeg_safely(proc, logf)
                        proc, logf = self._start_ffmpeg(width, height)
                        writer_state["proc"] = proc
                        writer_state["logf"] = logf
                        writer_state["last_restart"] = time.monotonic()
                        if proc is None:
                            return

                    try:
                        proc.stdin.write(pending.tobytes(order="C"))
                        self.frames_written += 1
                        self.last_write_monotonic = time.monotonic()
                        pending = None
                    except Exception as e:
                        if writer_stop.is_set() or self.stop_event.is_set():
                            break
                        self.last_error = f"FFmpeg pipe error ({e}); restarting encoder. See log: {self.ffmpeg_log}"
                        self._stop_ffmpeg_safely(proc, logf)
                        proc, logf = self._start_ffmpeg(width, height)
                        writer_state["proc"] = proc
                        writer_state["logf"] = logf
                        writer_state["last_restart"] = time.monotonic()
                        if proc is None:
                            return
                        # Keep 'pending' and try writing it to the fresh FFmpeg process.

                except Exception as e:
                    self.last_error = f"FFmpeg writer-loop error: {e}. See log: {self.ffmpeg_log}"
                    break

            self._stop_ffmpeg_safely(proc, logf)
            writer_state["proc"] = None
            writer_state["logf"] = None

        try:
            # Timestamp file is streamed continuously instead of held in RAM.
            timestamp_f = open(self.timestamps_path, "a", encoding="utf-8", buffering=1)
            timestamp_f.write(f"# Camera timestamps start {dt.datetime.now().isoformat()}\n")

            cam_list = system.GetCameras()
            if cam_list.GetSize() == 0:
                self.last_error = "No cameras detected by PySpin."
                return

            cam = cam_list.GetByIndex(0)
            cam.Init()
            nodemap = cam.GetNodeMap()

            if self.force_external_trigger:
                try_set_enum(nodemap, "TriggerMode", "Off")

            try_set_enum(nodemap, "PixelFormat", "Mono8")
            try_set_enum(nodemap, "AcquisitionMode", "Continuous")
            set_centered_roi(nodemap, self.target_width, self.target_height)

            if self.force_external_trigger:
                self.camera_config_report = configure_camera_external_trigger(
                    nodemap,
                    source=self.trigger_source,
                    activation=self.trigger_activation,
                    delay_us=self.trigger_delay_us,
                    overlap="ReadOut",
                )
            else:
                self.camera_config_report = {
                    "external_trigger_forced": False,
                    "readback": {
                        "TriggerMode": try_get_enum(nodemap, "TriggerMode"),
                        "TriggerSource": try_get_enum(nodemap, "TriggerSource"),
                    },
                }

            cam.BeginAcquisition()

            while not self.stop_event.is_set():
                image = None
                try:
                    image = cam.GetNextImage(1000)
                    if image.IsIncomplete():
                        continue

                    ts = image.GetTimeStamp()
                    self.last_frame_monotonic = time.monotonic()
                    try:
                        timestamp_f.write(f"{ts}\n")
                    except Exception:
                        pass

                    if image.GetPixelFormatName() != "Mono8":
                        converted = image.Convert(PySpin.PixelFormat_Mono8, PySpin.HQ_LINEAR)
                        frame = converted.GetNDArray()
                        converted.Release()
                    else:
                        frame = image.GetNDArray()

                    if frame.ndim != 2:
                        continue

                    if self.actual_width is None:
                        self.actual_height, self.actual_width = frame.shape
                        desired = (self.target_width, self.target_height)
                        actual = (self.actual_width, self.actual_height)

                        if desired[0] and desired[1]:
                            if actual == desired:
                                self.record_width, self.record_height = actual
                            else:
                                self.record_width, self.record_height = desired if self.software_resize_if_needed else actual
                        else:
                            self.record_width, self.record_height = actual

                        writer_thread = threading.Thread(
                            target=writer_loop,
                            args=(int(self.record_width), int(self.record_height)),
                            daemon=True,
                        )
                        writer_thread.start()

                    self.waiting_for_first_frame = False
                    self.frames_total += 1

                    if (self.record_width, self.record_height) != (self.actual_width, self.actual_height):
                        frame_out = cv2.resize(frame, (self.record_width, self.record_height), interpolation=cv2.INTER_AREA)
                    else:
                        frame_out = frame
                    frame_out = np.ascontiguousarray(frame_out)

                    # Preview is updated before FFmpeg writing. If the encoder dies or blocks,
                    # the live preview still tells us whether the camera is receiving TTL frames.
                    if self.preview_enabled:
                        now = time.monotonic()
                        if now - last_preview_update >= (1.0 / self.preview_max_fps):
                            last_preview_update = now
                            ui = frame_out
                            max_side = 640
                            if max(ui.shape) > max_side:
                                scale = max_side / max(ui.shape)
                                new_w = max(1, int(ui.shape[1] * scale))
                                new_h = max(1, int(ui.shape[0] * scale))
                                ui = cv2.resize(ui, (new_w, new_h), interpolation=cv2.INTER_AREA)
                            with self._preview_lock:
                                self._preview_frame = ui.copy()

                    self.writer_queue_size = writer_q.qsize()
                    try:
                        writer_q.put_nowait(frame_out.copy())
                    except queue.Full:
                        self.frames_dropped += 1
                        self.last_error = (
                            f"FFmpeg writer queue full; dropped {self.frames_dropped} frame(s). "
                            f"See log: {self.ffmpeg_log}"
                        )
                        stop_proc_from_watchdog("writer queue full")

                    # If FFmpeg stops consuming frames, kill/restart it rather than allowing
                    # the acquisition thread to freeze forever.
                    if writer_q.qsize() > 0 and self.last_write_monotonic > 0:
                        age = time.monotonic() - self.last_write_monotonic
                        if age > 30:
                            self.last_error = f"FFmpeg stalled for {age:.1f}s; watchdog restarting encoder."
                            stop_proc_from_watchdog(self.last_error)
                            self.last_write_monotonic = time.monotonic()

                except PySpin.SpinnakerException as e:
                    if self._is_timeout_exc(e):
                        continue
                    self.last_error = f"PySpin error: {e}"
                    break
                finally:
                    if image is not None:
                        try:
                            image.Release()
                        except Exception:
                            pass

            try:
                cam.EndAcquisition()
            except Exception:
                pass
            try:
                cam.DeInit()
            except Exception:
                pass

        finally:
            writer_stop.set()
            try:
                writer_q.put_nowait(None)
            except Exception:
                pass

            if writer_thread is not None:
                try:
                    writer_thread.join(timeout=30)
                except Exception:
                    pass

            # If writer thread did not stop because FFmpeg was stuck in stdin.write,
            # kill FFmpeg and let the thread unwind.
            try:
                p = writer_state.get("proc")
                if p is not None and p.poll() is None:
                    try:
                        p.kill()
                    except Exception:
                        pass
            except Exception:
                pass

            if timestamp_f:
                try:
                    timestamp_f.write(f"# Camera timestamps end {dt.datetime.now().isoformat()}\n")
                    timestamp_f.flush()
                    timestamp_f.close()
                except Exception:
                    pass

            try:
                if cam_list is not None:
                    cam_list.Clear()
            except Exception:
                pass

            cam = None
            cam_list = None
            proc = None
            logf = None
            gc.collect()


# -----------------------------
# Arduino trigger controller
# -----------------------------
class ArduinoTrigger:
    def __init__(self):
        self._thread: Optional[threading.Thread] = None
        self._stop = threading.Event()
        self.status = "Idle."

    def is_running(self) -> bool:
        return self._thread is not None and self._thread.is_alive()

    def request_stop(self) -> None:
        self._stop.set()

    def start_one_shot(self, port: str, baud: int, freq_hz: int, pulse_ms: int, count: int):
        if self.is_running():
            return
        self._stop.clear()
        self.status = "Starting..."
        self._thread = threading.Thread(
            target=self._run,
            args=(port, baud, freq_hz, pulse_ms, count),
            daemon=True
        )
        self._thread.start()

    def _run(self, port: str, baud: int, freq_hz: int, pulse_ms: int, count: int):
        try:
            self.status = f"Opening {port}..."
            ser = serial.Serial(port, baud, timeout=1)
            time.sleep(2.0)
            try:
                ser.reset_input_buffer()
            except Exception:
                pass

            cmd = f"{freq_hz} {pulse_ms} {count}\n"
            ser.write(cmd.encode("ascii"))
            try:
                ser.flush()
            except Exception:
                pass
            self.status = f"Sent: {cmd.strip()} | waiting DONE..."

            expected_s = (count / max(1, freq_hz)) + 5.0
            deadline = time.time() + (expected_s * 2.0)

            while not self._stop.is_set() and time.time() < deadline:
                line = ser.readline().decode(errors="ignore").strip()
                if line == "DONE":
                    self.status = "DONE."
                    break

            if self._stop.is_set():
                self.status = "Cancelled."
            elif self.status != "DONE.":
                self.status = "Timeout waiting for DONE."

            try:
                ser.close()
            except Exception:
                pass

        except Exception as e:
            self.status = f"Error: {e}"



# -----------------------------
# Environmental controller (Arduino control box)
# -----------------------------
class EnvironmentalController:
    """Controls the DeepEcoHAB environmental Arduino (light/dark cycle + DHT22 logging).

    Supports both protocols:
      - Legacy GUI script:  CONFIG,<HH:MM>,<HH:MM>,<interval_min>,<phase_flag>
                            TIME,<DD-MM-YYYY>,<HH:MM:SS>
      - Current firmware:   LIGHTPHASE:HH:MM-HH:MM
                            LOGINTERVAL:<minutes>
                            PHASELOG:<0|1>
                            TIME:YYYY-MM-DD HH:MM:SS
    The firmware emits log rows as:
      LOG:DD-MM-YYYY,HH:MM:SS,Light/Dark,<temp>,<hum>[,phase_switch]
    """

    def __init__(self):
        self._thread: Optional[threading.Thread] = None
        self._stop = threading.Event()
        self._lock = threading.Lock()

        self._ser: Optional[serial.Serial] = None
        self.status: str = "Idle."

        self.last_record: Optional[Dict[str, Any]] = None
        self.lines_raw: int = 0
        self.lines_parsed: int = 0

        self._experiment_log_path: Optional[Path] = None

    def is_running(self) -> bool:
        return self._thread is not None and self._thread.is_alive()

    def set_experiment_log_path(self, path: Optional[Path]) -> None:
        with self._lock:
            self._experiment_log_path = Path(path) if path else None

        if path:
            try:
                p = Path(path)
                p.parent.mkdir(parents=True, exist_ok=True)
                if not p.exists() or p.stat().st_size == 0:
                    with open(p, "w", newline="", encoding="utf-8") as f:
                        f.write("iso_datetime,date,time,phase,temperature_C,humidity_percent,phase_switch\n")
            except Exception:
                pass

    def start(
        self,
        port: str,
        baud: int,
        light_start_hhmm: str,
        light_end_hhmm: str,
        log_interval_min: int,
        phase_switch_extra: bool,
    ) -> None:
        if self.is_running():
            return
        self._stop.clear()
        self.status = "Opening..."

        self._thread = threading.Thread(
            target=self._run,
            args=(port, baud, light_start_hhmm, light_end_hhmm, log_interval_min, phase_switch_extra),
            daemon=True,
        )
        self._thread.start()

    def stop(self) -> None:
        self._stop.set()
        try:
            if self._ser and self._ser.is_open:
                try:
                    self._ser.write(b"STOP\n")
                    self._ser.flush()
                except Exception:
                    pass
        except Exception:
            pass

    # ---- internals ----
    def _send_init(
        self,
        ser: serial.Serial,
        light_start_hhmm: str,
        light_end_hhmm: str,
        log_interval_min: int,
        phase_switch_extra: bool,
    ) -> bool:
        """Send initialization commands and wait briefly for an ACK.

        This is aligned with the Arduino firmware in DeepEcoHAB_control_box_sotfware_06_02_2025.ino
        (TIME:/LIGHTPHASE:/LOGINTERVAL:/PHASELOG:/START)."""
        phase_flag = 1 if phase_switch_extra else 0

        def write_line(s: str, delay_s: float = 0.08) -> None:
            ser.write((s + "\n").encode("utf-8"))
            try:
                ser.flush()
            except Exception:
                pass
            time.sleep(delay_s)

        # Clear any boot-time text so we don't mis-detect ACKs
        try:
            ser.reset_input_buffer()
        except Exception:
            pass

        # Prefer the current firmware protocol first
        now = dt.datetime.now()
        sent_any = False
        try:
            write_line(f"LIGHTPHASE:{light_start_hhmm}-{light_end_hhmm}")
            write_line(f"LOGINTERVAL:{int(log_interval_min)}")
            write_line(f"PHASELOG:{phase_flag}")
            write_line(f"TIME:{now.strftime('%Y-%m-%d')} {now.strftime('%H:%M:%S')}")
            write_line("START")
            sent_any = True
        except Exception:
            sent_any = False

        # Briefly wait for a clear START ACK
        def wait_for_start_ack(timeout_s: float) -> bool:
            deadline = time.time() + float(timeout_s)
            while time.time() < deadline and not self._stop.is_set():
                try:
                    raw = ser.readline()
                    if not raw:
                        continue
                    line = raw.decode("utf-8", errors="ignore").strip()
                except Exception:
                    continue
                if not line:
                    continue
                if "START command received" in line or "Execution started" in line:
                    return True
            return False

        if sent_any and wait_for_start_ack(3.0):
            return True

        # Fallback for older firmware (legacy CONFIG/TIME/START), e.g. from DeepEcoHAB_control_box_RTC_added_v4.py
        try:
            now = dt.datetime.now()
            write_line(f"CONFIG,{light_start_hhmm},{light_end_hhmm},{int(log_interval_min)},{phase_flag}")
            write_line(f"TIME,{now.strftime('%d-%m-%Y')},{now.strftime('%H:%M:%S')}")
            write_line("START")
        except Exception:
            pass

        return wait_for_start_ack(2.0)

    def _parse_log_line(self, line: str) -> Optional[Dict[str, Any]]:
        if not (line.startswith("LOG:") or line.startswith("LOG,")):
            return None
        payload = line[4:]  # after LOG: or LOG,
        if "Date[" in payload or payload.startswith("Date["):
            return None
        parts = [p.strip() for p in payload.split(",")]

        if len(parts) < 5:
            return None

        date_s, time_s, phase_s, temp_s, hum_s = parts[:5]
        phase_switch = any("phase_switch" in p for p in parts[5:])

        def to_float(x: str) -> float:
            try:
                return float(x)
            except Exception:
                return float("nan")

        temp = to_float(temp_s)
        hum = to_float(hum_s)

        iso_dt = ""
        try:
            # DD-MM-YYYY + HH:MM:SS
            d = dt.datetime.strptime(f"{date_s} {time_s}", "%d-%m-%Y %H:%M:%S")
            iso_dt = d.isoformat()
        except Exception:
            pass

        return {
            "iso_datetime": iso_dt,
            "date": date_s,
            "time": time_s,
            "phase": phase_s,
            "temperature_C": temp,
            "humidity_percent": hum,
            "phase_switch": bool(phase_switch),
        }

    def _append_record(self, rec: Dict[str, Any]) -> None:
        with self._lock:
            p = self._experiment_log_path

        if not p:
            return

        try:
            Path(p).parent.mkdir(parents=True, exist_ok=True)
            with open(p, "a", newline="", encoding="utf-8") as f:
                f.write(
                    f"{rec.get('iso_datetime','')},{rec.get('date','')},{rec.get('time','')},{rec.get('phase','')},"
                    f"{rec.get('temperature_C','')},{rec.get('humidity_percent','')},{int(bool(rec.get('phase_switch')))}\n"
                )
        except Exception:
            pass

    def _run(
        self,
        port: str,
        baud: int,
        light_start_hhmm: str,
        light_end_hhmm: str,
        log_interval_min: int,
        phase_switch_extra: bool,
    ):
        ser = None
        try:
            self.status = f"Opening {port}..."
            ser = serial.Serial(port, baud, timeout=1)
            time.sleep(2.0)  # allow reset
            self._ser = ser

            self.status = "Configuring (sending init)..."
            ok = self._send_init(ser, light_start_hhmm, light_end_hhmm, log_interval_min, phase_switch_extra)
            self.status = "Running." if ok else "No START ACK (check COM/baud/protocol)."

            while not self._stop.is_set():
                try:
                    raw = ser.readline()
                    if not raw:
                        continue
                    line = raw.decode("utf-8", errors="ignore").strip()
                    if not line:
                        continue

                    # Non-LOG feedback/ACK lines from the controller
                    if "START command received" in line or "Execution started" in line:
                        self.status = "Running."
                        continue

                    self.lines_raw += 1

                    rec = self._parse_log_line(line)
                    if rec:
                        self.lines_parsed += 1
                        with self._lock:
                            self.last_record = rec
                        self._append_record(rec)
                except Exception:
                    time.sleep(0.1)

        except Exception as e:
            self.status = f"Error: {e}"
        finally:
            try:
                if ser and ser.is_open:
                    try:
                        ser.write(b"STOP\n")
                        ser.flush()
                    except Exception:
                        pass
                    ser.close()
            except Exception:
                pass
            self._ser = None
            if self._stop.is_set() and not self.status.startswith("Error"):
                self.status = "Stopped."


# -----------------------------
# Animal Details Window
# -----------------------------
class AnimalDetailsDialog(QDialog):
    MATCH_TIMEOUT_S = 90

    def __init__(self, main: "MainWindow"):
        super().__init__(main)
        self.main = main
        self.setWindowTitle("Animal details")
        self.resize(1120, 720)
        self._sync_guard = False
        self._same_guard = False

        self.waiting_row: Optional[int] = None
        self.waiting_remaining: int = 0
        self.waiting_start_counter: Optional[int] = None
        self._direct_thread: Optional[threading.Thread] = None
        self._direct_result: Dict[str, Any] = {"done": False, "tag": None}
        self._direct_deadline: float = 0.0

        self._mouse_widgets: List[Dict[str, Any]] = []

        self._build_ui()
        self._connect_sync()
        self._rebuild_rows(self.n_mice_spin.value())

        self.poll_timer = QTimer(self)
        self.poll_timer.setInterval(200)
        self.poll_timer.timeout.connect(self._poll_match)

        self.countdown_timer = QTimer(self)
        self.countdown_timer.setInterval(1000)
        self.countdown_timer.timeout.connect(self._tick_countdown)

    def _build_ui(self):
        root = QWidget()
        lay = QVBoxLayout(root)
        lay.setContentsMargins(10, 10, 10, 10)
        lay.setSpacing(10)
        self.setLayout(lay)

        top = QHBoxLayout()
        top.addWidget(QLabel("Experiment name:"))
        self.exp_name_edit = QLineEdit(self.main.exp_edit.text())
        self.exp_name_edit.setMaximumWidth(340)
        top.addWidget(self.exp_name_edit)

        self.btn_import = QPushButton("Import JSON")
        self.btn_import.clicked.connect(self._import_json)
        top.addWidget(self.btn_import)

        self.btn_export_both = QPushButton("Export to CSV & JSON")
        self.btn_export_both.clicked.connect(lambda: self._export_details(fmt="csv"))
        top.addWidget(self.btn_export_both)

        top.addStretch(1)
        lay.addLayout(top)

        nm = QHBoxLayout()
        nm.addWidget(QLabel("Number of mice in the experiment:"))
        self.n_mice_spin = make_spinbox(1, 50, 12)
        self.n_mice_spin.valueChanged.connect(lambda v: self._rebuild_rows(int(v)))
        nm.addWidget(self.n_mice_spin)
        nm.addStretch(1)
        lay.addLayout(nm)

        # Same-for-all row
        same_box = QGroupBox("Same for all")
        sg = QGridLayout(same_box)
        sg.setContentsMargins(8, 8, 8, 8)
        sg.setHorizontalSpacing(10)
        sg.setVerticalSpacing(4)

        self.same_line = QCheckBox("Mouse line")
        self.same_geno = QCheckBox("Genotype")
        self.same_sex = QCheckBox("Sex")
        self.same_dob = QCheckBox("Date of birth")
        sg.addWidget(self.same_line, 0, 0)
        sg.addWidget(self.same_geno, 0, 1)
        sg.addWidget(self.same_sex, 0, 2)
        sg.addWidget(self.same_dob, 0, 3)
        sg.setColumnStretch(4, 1)

        self.same_line.toggled.connect(lambda _: self._apply_same_all("line"))
        self.same_geno.toggled.connect(lambda _: self._apply_same_all("geno"))
        self.same_sex.toggled.connect(lambda _: self._apply_same_all("sex"))
        self.same_dob.toggled.connect(lambda _: self._apply_same_all("dob"))

        lay.addWidget(same_box)

        self.status_lbl = QLabel("Ready.")
        lay.addWidget(self.status_lbl)

        self.table = QTableWidget(0, 8)
        self.table.setHorizontalHeaderLabels([
            "No.", "Mouse line", "Genotype", "Number", "Sex", "Date of birth", "Tag no.", "Match tag"
        ])
        self.table.verticalHeader().setVisible(False)
        self.table.setSortingEnabled(False)
        self.table.setEditTriggers(QTableWidget.NoEditTriggers)
        self.table.setSelectionMode(QAbstractItemView.NoSelection)

        self.table.setColumnWidth(0, 50)
        self.table.setColumnWidth(1, 170)
        self.table.setColumnWidth(2, 170)
        self.table.setColumnWidth(3, 90)
        self.table.setColumnWidth(4, 85)
        self.table.setColumnWidth(5, 140)
        self.table.setColumnWidth(6, 220)
        self.table.setColumnWidth(7, 130)

        lay.addWidget(self.table, 1)

        hint = QLabel(
            "Match tag: press the row's button, then pass the animal through any RFID antenna. "
            "The software waits 90 seconds and shows a countdown."
        )
        hint.setStyleSheet("color:#555;")
        lay.addWidget(hint)

    def _connect_sync(self):
        def from_main(txt: str):
            if self._sync_guard: return
            self._sync_guard = True
            try:
                if self.exp_name_edit.text() != txt:
                    self.exp_name_edit.setText(txt)
            finally:
                self._sync_guard = False

        def from_dialog(txt: str):
            if self._sync_guard: return
            self._sync_guard = True
            try:
                if self.main.exp_edit.text() != txt:
                    self.main.exp_edit.setText(txt)
            finally:
                self._sync_guard = False

        self.main.exp_edit.textChanged.connect(from_main)
        self.exp_name_edit.textChanged.connect(from_dialog)

    def _gather_row_data(self) -> List[Dict[str, Any]]:
        out = []
        for w in self._mouse_widgets:
            out.append({
                "mouse_line": w["line"].text(),
                "genotype": w["geno"].text(),
                "number": w["number"].text(),
                "sex": w["sex"].currentText(),
                "dob": w["dob"].date().toString("yyyy-MM-dd"),
                "tag": w["tag"].text(),
            })
        return out

    def _disconnect_first_row_signals(self):
        # Best-effort safe disconnect (Qt raises if not connected)
        if not self._mouse_widgets:
            return
        r0 = self._mouse_widgets[0]
        for sig, fn in [
            (r0["line"].textChanged, self._same_line_from_first),
            (r0["geno"].textChanged, self._same_geno_from_first),
            (r0["sex"].currentTextChanged, self._same_sex_from_first),
            (r0["dob"].dateChanged, self._same_dob_from_first),
        ]:
            try:
                sig.disconnect(fn)
            except Exception:
                pass

    def _connect_first_row_signals(self):
        if not self._mouse_widgets:
            return
        r0 = self._mouse_widgets[0]
        r0["line"].textChanged.connect(self._same_line_from_first)
        r0["geno"].textChanged.connect(self._same_geno_from_first)
        r0["sex"].currentTextChanged.connect(self._same_sex_from_first)
        r0["dob"].dateChanged.connect(self._same_dob_from_first)

    def _rebuild_rows(self, n: int):
        n = max(1, min(50, int(n)))
        old = self._gather_row_data()

        self._disconnect_first_row_signals()

        self.table.setRowCount(n)
        self._mouse_widgets = []

        for r in range(n):
            row: Dict[str, Any] = {}

            item = QTableWidgetItem(str(r + 1))
            item.setTextAlignment(Qt.AlignCenter)
            self.table.setItem(r, 0, item)

            line = QLineEdit()
            self.table.setCellWidget(r, 1, line)
            row["line"] = line

            geno = QLineEdit()
            self.table.setCellWidget(r, 2, geno)
            row["geno"] = geno

            number = QLineEdit()
            self.table.setCellWidget(r, 3, number)
            row["number"] = number

            sex = QComboBox()
            sex.addItems(["Male", "Female"])
            self.table.setCellWidget(r, 4, sex)
            row["sex"] = sex

            dob = QDateEdit()
            dob.setCalendarPopup(True)
            dob.setDisplayFormat("yyyy-MM-dd")
            dob.setDate(QDate.currentDate())
            self.table.setCellWidget(r, 5, dob)
            row["dob"] = dob

            tag = QLineEdit()
            tag.setMaxLength(64)
            self.table.setCellWidget(r, 6, tag)
            row["tag"] = tag

            btn = QPushButton("Match tag")
            btn.clicked.connect(lambda _=False, rr=r: self._on_match_tag(rr))
            self.table.setCellWidget(r, 7, btn)
            row["match"] = btn

            self._mouse_widgets.append(row)

        for r in range(min(len(old), n)):
            self._mouse_widgets[r]["line"].setText(old[r].get("mouse_line", ""))
            self._mouse_widgets[r]["geno"].setText(old[r].get("genotype", ""))
            self._mouse_widgets[r]["number"].setText(old[r].get("number", ""))
            sex_txt = old[r].get("sex", "Male")
            self._mouse_widgets[r]["sex"].setCurrentText(sex_txt if sex_txt in ("Male", "Female") else "Male")
            dob_txt = old[r].get("dob", "")
            if dob_txt:
                try:
                    y, m, d = [int(x) for x in dob_txt.split("-")]
                    self._mouse_widgets[r]["dob"].setDate(QDate(y, m, d))
                except Exception:
                    pass
            self._mouse_widgets[r]["tag"].setText(old[r].get("tag", ""))

        self._connect_first_row_signals()
        self._apply_same_all("line")
        self._apply_same_all("geno")
        self._apply_same_all("sex")
        self._apply_same_all("dob")

        self.status_lbl.setText(f"Ready. Rows: {n}")

    # ---- Same-for-all propagation ----
    def _same_line_from_first(self, txt: str):
        if self.same_line.isChecked():
            self._apply_same_all("line")

    def _same_geno_from_first(self, txt: str):
        if self.same_geno.isChecked():
            self._apply_same_all("geno")

    def _same_sex_from_first(self, txt: str):
        if self.same_sex.isChecked():
            self._apply_same_all("sex")

    def _same_dob_from_first(self, _d: QDate):
        if self.same_dob.isChecked():
            self._apply_same_all("dob")

    def _apply_same_all(self, field: str):
        if self._same_guard:
            return
        if not self._mouse_widgets:
            return
        self._same_guard = True
        try:
            r0 = self._mouse_widgets[0]
            if field == "line" and self.same_line.isChecked():
                val = r0["line"].text()
                for r in self._mouse_widgets[1:]:
                    if r["line"].text() != val:
                        r["line"].setText(val)
            if field == "geno" and self.same_geno.isChecked():
                val = r0["geno"].text()
                for r in self._mouse_widgets[1:]:
                    if r["geno"].text() != val:
                        r["geno"].setText(val)
            if field == "sex" and self.same_sex.isChecked():
                val = r0["sex"].currentText()
                for r in self._mouse_widgets[1:]:
                    if r["sex"].currentText() != val:
                        r["sex"].setCurrentText(val)
            if field == "dob" and self.same_dob.isChecked():
                val = r0["dob"].date()
                for r in self._mouse_widgets[1:]:
                    if r["dob"].date() != val:
                        r["dob"].setDate(val)
        finally:
            self._same_guard = False

    # ---- Match tag ----
    def _set_waiting_text(self, row: int, remaining: int):
        self._mouse_widgets[row]["match"].setText(f"Waiting: {remaining}")

    def _reset_btn(self, row: int):
        self._mouse_widgets[row]["match"].setText("Match tag")

    def _cancel_wait(self, reason: str):
        if self.waiting_row is None:
            return
        row = self.waiting_row
        self.waiting_row = None
        self.waiting_remaining = 0
        self.waiting_start_counter = None
        self._direct_thread = None
        self._direct_result = {"done": False, "tag": None}
        self._direct_deadline = 0.0
        self.poll_timer.stop()
        self.countdown_timer.stop()
        self._reset_btn(row)
        self.status_lbl.setText(reason)

    def _on_match_tag(self, row: int):
        if self.waiting_row is not None:
            if self.waiting_row == row:
                self._cancel_wait("Match tag: cancelled.")
                return
            QMessageBox.information(self, "Already waiting", "Already waiting on another row.")
            return

        daq_port = self.main.daq_combo.currentText().strip()
        if not daq_port:
            QMessageBox.critical(self, "Missing DAQ COM", "Select the DAQ COM port in the main window.")
            return

        self.waiting_row = row
        self.waiting_remaining = self.MATCH_TIMEOUT_S
        self._set_waiting_text(row, self.waiting_remaining)

        if self.main.board and self.main.board.is_running():
            start_counter, _, _ = self.main.board.get_last_rfid_event()
            self.waiting_start_counter = start_counter
            self.status_lbl.setText(f"Waiting for next RFID tag (row {row+1})... (DAQ running)")
            self.poll_timer.start()
            self.countdown_timer.start()
            return

        self._direct_result = {"done": False, "tag": None}
        self._direct_deadline = time.time() + self.MATCH_TIMEOUT_S

        def _worker():
            evt = read_one_rfid_event_from_port(daq_port, timeout_s=self.MATCH_TIMEOUT_S)
            self._direct_result["tag"] = (evt[1] if evt else None)
            self._direct_result["done"] = True

        self._direct_thread = threading.Thread(target=_worker, daemon=True)
        self._direct_thread.start()
        self.status_lbl.setText(f"Waiting for RFID tag (row {row+1})... (direct read)")
        self.poll_timer.start()
        self.countdown_timer.start()

    def _tick_countdown(self):
        if self.waiting_row is None:
            self.countdown_timer.stop()
            return
        self.waiting_remaining = max(0, self.waiting_remaining - 1)
        self._set_waiting_text(self.waiting_row, self.waiting_remaining)
        if self.waiting_remaining <= 0:
            self._cancel_wait("Match tag: timeout (90s).")

    def _poll_match(self):
        if self.waiting_row is None:
            self.poll_timer.stop()
            return

        if self.main.board and self.main.board.is_running() and self.waiting_start_counter is not None:
            cur_counter, tag, ch = self.main.board.get_last_rfid_event()
            if cur_counter > self.waiting_start_counter and tag:
                row = self.waiting_row
                self._mouse_widgets[row]["tag"].setText(tag)
                self._cancel_wait(f"Captured tag {tag} (antenna {ch}) for row {row+1}.")
            return

        if self._direct_thread is not None:
            if self._direct_result.get("done", False):
                row = self.waiting_row
                tag = self._direct_result.get("tag", None)
                if tag:
                    self._mouse_widgets[row]["tag"].setText(tag)
                    self._cancel_wait(f"Captured tag {tag} for row {row+1}.")
                else:
                    self._cancel_wait("Match tag: no tag detected (timeout).")
            else:
                if time.time() > self._direct_deadline + 5:
                    self._cancel_wait("Match tag: timeout (thread).")

    # ---- Import / Export shared config ----
    def _animals_payload(self) -> Dict[str, Any]:
        rows: Dict[str, Dict[str, Any]] = {}
        for i, w in enumerate(self._mouse_widgets, start=1):
            tag = w["tag"].text().strip()
            key = tag if tag else f"row_{i}"
            rows[key] = {
                "row_index": i,
                "mouse_line": w["line"].text().strip(),
                "genotype": w["geno"].text().strip(),
                "number": w["number"].text().strip(),
                "sex": w["sex"].currentText(),
                "date_of_birth": w["dob"].date().toString("yyyy-MM-dd"),
                "tag_no": tag,
            }
        return {"n_mice": int(self.n_mice_spin.value()), "rows": rows}

    def _export_details(self, fmt: str):
        try:
            self.main.update_shared_config(animals=self._animals_payload(), layout=None)
            csv_path, json_path = self.main.get_shared_config_paths()
            if fmt.lower() == "json":
                QMessageBox.information(self, "Exported", f"Updated JSON:\n{json_path}")
            else:
                QMessageBox.information(self, "Exported", f"Updated CSV:\n{csv_path}\n(and JSON:\n{json_path})")
        except Exception as e:
            QMessageBox.critical(self, "Export failed", str(e))

    def _import_json(self):
        path, _ = QFileDialog.getOpenFileName(self, "Import config JSON", self.main.save_edit.text(), "JSON files (*.json)")
        if not path:
            return
        cfg = self.main.load_shared_config_from_file(Path(path))
        if not cfg:
            QMessageBox.critical(self, "Import failed", "Could not read JSON.")
            return

        # Do not overwrite the current experiment name or output directory when loading a template.
        animals = cfg.get("animals") or {}
        rows = _animal_rows_as_list(animals)
        n = int(animals.get("n_mice") or 0) or len(rows) or 12
        n = max(1, min(50, n))
        self.n_mice_spin.setValue(n)

        # rebuild already happened by setValue, now fill
        for r in range(min(n, len(rows))):
            rr = rows[r]
            self._mouse_widgets[r]["line"].setText(rr.get("mouse_line", ""))
            self._mouse_widgets[r]["geno"].setText(rr.get("genotype", ""))
            self._mouse_widgets[r]["number"].setText(rr.get("number", ""))
            sx = rr.get("sex", "Male")
            self._mouse_widgets[r]["sex"].setCurrentText(sx if sx in ("Male", "Female") else "Male")
            dob = rr.get("date_of_birth", "")
            if dob:
                try:
                    y, m, d = [int(x) for x in dob.split("-")]
                    self._mouse_widgets[r]["dob"].setDate(QDate(y, m, d))
                except Exception:
                    pass
            self._mouse_widgets[r]["tag"].setText(rr.get("tag_no", ""))

        self.status_lbl.setText(f"Imported animals from: {Path(path).name}")

    def closeEvent(self, event):
        self._cancel_wait("Closed.")
        super().closeEvent(event)


# -----------------------------
# Layout Editor (QGraphicsView) + shared config export/import
# -----------------------------
class LayoutDialog(QDialog):
    GRID_N = 7
    CELL = 155
    MARGIN = 14
    CHECK_TIMEOUT_S = 90
    DEFAULT_ANTENNAS_PER_TUNNEL = 2

    def __init__(self, main: "MainWindow"):
        super().__init__(main)
        self.main = main
        self.setWindowTitle("DeepEcoHAB layout")
        self.resize(1180, 900)

        self.scene = QGraphicsScene(self)
        self.view = QGraphicsView(self.scene)
        self.view.setRenderHints(QPainter.Antialiasing | QPainter.TextAntialiasing)
        self.view.setDragMode(QGraphicsView.NoDrag)
        self.view.setBackgroundBrush(QBrush(QColor("#0f1115")))

        self.mode = "cage"  # cage | tunnel | select

        self.cells: Dict[Tuple[int, int], LayoutDialog.CellItem] = {}
        self.tunnels: List[LayoutDialog.TunnelItem] = []
        self.selected_tunnel: Optional[LayoutDialog.TunnelItem] = None

        self._tunnel_start: Optional[Tuple[LayoutDialog.CellItem, QPointF]] = None
        self._active_editor_dot: Optional[LayoutDialog.AntennaDot] = None

        self.active_dot: Optional[LayoutDialog.AntennaDot] = None
        self.check_remaining: int = 0
        self.check_start_counter: Optional[int] = None
        self._direct_thread: Optional[threading.Thread] = None
        self._direct_result: Dict[str, Any] = {"done": False, "ch": None}
        self._direct_deadline: float = 0.0

        self._tunnel_serial = 1

        # fonts (bigger)
        self._font_antenna = QFont()
        self._font_antenna.setPointSize(11)  # smaller so labels don't overlap
        self._font_antenna.setBold(True)

        self._build_ui()
        self._build_grid()
        self._apply_default_layout()

        self.poll_timer = QTimer(self)
        self.poll_timer.setInterval(200)
        self.poll_timer.timeout.connect(self._poll_check)

        self.countdown_timer = QTimer(self)
        self.countdown_timer.setInterval(1000)
        self.countdown_timer.timeout.connect(self._tick_check)

    # -----------------------------
    @staticmethod
    def cell_id(r: int, c: int) -> str:
        return f"{c+1}{chr(ord('A')+r)}"

    def _rc_from_id(self, s: str) -> Tuple[int, int]:
        m = re.match(r"^([1-7])([A-G])$", s.strip().upper())
        if not m:
            raise ValueError(f"Bad cell id: {s}")
        c = int(m.group(1)) - 1
        r = ord(m.group(2)) - ord("A")
        return r, c

    # -----------------------------
